import { useState } from 'react';
import axios from 'axios';

function statusClass(s) {
  if (s === 'Pending')            return 'badge badge-pending';
  if (s === 'Processing')         return 'badge badge-processing';
  if (s === 'Verified')           return 'badge badge-verified';
  if (s === 'Passport Generated') return 'badge badge-generated';
  return 'badge badge-rejected';
}

const STATUS_STEPS = ['Pending', 'Processing', 'Verified', 'Passport Generated'];

export default function Status() {
  const [id, setId]       = useState('');
  const [data, setData]   = useState(null);
  const [error, setError] = useState(false);
  const [loading, setLoading] = useState(false);

  const fetchStatus = async () => {
    if (!id.trim()) return;
    setLoading(true); setError(false); setData(null);
    try {
      const res = await axios.get(`http://localhost:5000/applications/${id}`);
      setData(res.data);
    } catch {
      setError(true);
    } finally {
      setLoading(false);
    }
  };

  const stepIndex = data ? STATUS_STEPS.indexOf(data.status) : -1;

  return (
    <div className="page">
      <div className="container" style={{ maxWidth: 580 }}>
        <div className="page-header">
          <h2>Track Application</h2>
          <div className="divider" />
          <p>Enter your Application ID to check the current status.</p>
        </div>

        <div className="card">
          <div style={{ display: 'flex', gap: 10 }}>
            <input
              placeholder="Application ID"
              value={id}
              onChange={e => setId(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && fetchStatus()}
              style={{ margin: 0 }}
            />
            <button
              className="btn btn-primary"
              onClick={fetchStatus}
              disabled={loading}
              style={{ whiteSpace: 'nowrap' }}
            >
              {loading ? '…' : 'Check'}
            </button>
          </div>

          {error && (
            <div className="alert alert-error" style={{ marginTop: 18 }}>
              ⚠️ No application found for ID <strong>{id}</strong>.
            </div>
          )}

          {data && (
            <div className="info-block">
              <h3>Application #{data.application_id}</h3>

              {/* Progress Steps */}
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 0, margin: '18px 0 22px', flexWrap: 'wrap' }}>
                {STATUS_STEPS.map((step, i) => (
                  <div key={step} style={{ display: 'flex', alignItems: 'center' }}>
                    <div style={{
                      display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 5
                    }}>
                      <div style={{
                        width: 28, height: 28, borderRadius: '50%',
                        background: i <= stepIndex ? 'var(--navy)' : 'var(--border)',
                        color: i <= stepIndex ? '#fff' : 'var(--text-muted)',
                        display: 'grid', placeItems: 'center',
                        fontSize: '0.75rem', fontWeight: 700,
                        transition: 'all 0.3s',
                        boxShadow: i === stepIndex ? '0 0 0 3px rgba(10,34,64,0.2)' : 'none'
                      }}>
                        {i < stepIndex ? '✓' : i + 1}
                      </div>
                      <span style={{
                        fontSize: '0.68rem', fontWeight: i === stepIndex ? 700 : 400,
                        color: i <= stepIndex ? 'var(--navy)' : 'var(--text-muted)',
                        textAlign: 'center', maxWidth: 70
                      }}>{step}</span>
                    </div>
                    {i < STATUS_STEPS.length - 1 && (
                      <div style={{
                        width: 32, height: 2, margin: '0 4px',
                        background: i < stepIndex ? 'var(--navy)' : 'var(--border)',
                        marginBottom: 20
                      }} />
                    )}
                  </div>
                ))}
              </div>

              <div className="info-row">
                <span className="info-label">Documents</span>
                <span style={{ fontWeight: 600, color: data.documents_submitted ? 'var(--success)' : 'var(--warning)' }}>
                  {data.documents_submitted ? '✓ Submitted' : '✗ Not Submitted'}
                </span>
              </div>
              <div className="info-row">
                <span className="info-label">Police Verification</span>
                <span style={{ fontWeight: 500 }}>{data.police_verification}</span>
              </div>
              <div className="info-row">
                <span className="info-label">Current Status</span>
                <span className={statusClass(data.status)}>{data.status}</span>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
